import{_ as i,c as a,o as s,aN as n}from"./chunks/framework.CMIDsdwV.js";const u=JSON.parse('{"title":"OpenClaw 安装【Windows版】","description":"","frontmatter":{"title":"OpenClaw 安装【Windows版】","date":"2026-03-08","permalink":"/aigc/development/open-claw/install-windows","tags":["AI应用开发","OpenClaw"],"categories":["AI应用开发","OpenClaw"]},"headers":[],"relativePath":"AIGC/AI应用开发/03.OpenClaw/1_OpenClaw安装【Windows版】.md","filePath":"AIGC/AI应用开发/03.OpenClaw/1_OpenClaw安装【Windows版】.md","lastUpdated":1773075361000}'),l={name:"AIGC/AI应用开发/03.OpenClaw/1_OpenClaw安装【Windows版】.md"};function p(t,e,o,r,d,h){return s(),a("div",null,[...e[0]||(e[0]=[n('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /AIGC\\AI应用开发\\03.OpenClaw\\1_OpenClaw安装【Windows版】.md for this page in Markdown format</div><h1 id="openclaw-安装教程【windows版】" tabindex="-1">OpenClaw 安装教程【Windows版】 <a class="header-anchor" href="#openclaw-安装教程【windows版】" aria-label="Permalink to &quot;OpenClaw 安装教程【Windows版】&quot;">​</a></h1><h2 id="一、安装-node-js" tabindex="-1">一、安装 Node.js <a class="header-anchor" href="#一、安装-node-js" aria-label="Permalink to &quot;一、安装 Node.js&quot;">​</a></h2><blockquote><p>Node.js是一个开源的、跨平台的JavaScript运行环境，它允许开发者使用JavaScript来编写服务器端的代码。</p></blockquote><p>进入官网：</p><p><a href="https://nodejs.org/zh-cn/download" target="_blank" rel="noreferrer">https://nodejs.org/zh-cn/download</a></p><p>下载 Windows 版安装程序。</p><p>安装步骤：</p><ol><li>打开安装包</li><li>勾选同意协议</li><li>一路点击 Next</li><li>点击 Install</li><li>完成后点击 Finish</li></ol><p>安装完成后，查看安装的版本：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Node.js 安装完成。</p><h2 id="二、安装-git" tabindex="-1">二、安装 Git <a class="header-anchor" href="#二、安装-git" aria-label="Permalink to &quot;二、安装 Git&quot;">​</a></h2><blockquote><p>Git 是一种<strong>分布式版本控制系统</strong>，核心作用是帮助个人或团队高效管理文件版本、协作开发，并保障代码安全。</p></blockquote><p>进入官网：</p><p><a href="https://git-scm.com/install/windows" target="_blank" rel="noreferrer">https://git-scm.com/install/windows</a> ，下载对应版本，例如“Git for Windows/x64 Setup”。</p><p>安装步骤：</p><ol><li>打开安装包</li><li>一路点击 Next</li><li>点击 Install</li><li>安装完成后，可以取消勾选 View Release Note</li><li>点击 Finish</li></ol><p>回车执行，等待安装完成，查看版本：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Git 安装完成。</p><h2 id="三、安装-openclaw" tabindex="-1">三、安装 OpenClaw <a class="header-anchor" href="#三、安装-openclaw" aria-label="Permalink to &quot;三、安装 OpenClaw&quot;">​</a></h2><p>在系统中搜索 PowerShell，选择以管理员身份运行。</p><p>先输入命令：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Set-ExecutionPolicy</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ExecutionPolicy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> RemoteSigned</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Scope</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CurrentUser</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果出现询问输入 Y 确认。</p><p>然后执行安装命令：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">iwr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -useb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://openclaw.ai/install.ps1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> iex</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>等待安装完成。</p><p>如果看到 OpenClaw 的欢迎信息，说明安装成功。</p><p>通过下面的命令，可以查看安装的版本：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="四、初始化配置-openclaw" tabindex="-1">四、初始化配置 OpenClaw <a class="header-anchor" href="#四、初始化配置-openclaw" aria-label="Permalink to &quot;四、初始化配置 OpenClaw&quot;">​</a></h2><p>启动初始化配置向导：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> onboard</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Openclaw 会提示风险 <code>I understand this is personal-by-default and shared/multi-user use requires lock-down. Continue?</code></p><ul><li><p>风险提示：按键盘上的左右方向键选择，Yes</p></li><li><p>Onboarding mode（模式）：QuickStart</p></li><li><p>Model/auth provider（模型服务商）：任选（如 OpenAI / Anthropic / Moonshot AI (Kimi K2.5)）</p></li><li><p>Select channel（通讯渠道）：Skip for now</p></li><li><p>Configure skills now（技能）：按空格选择 Skip for now</p></li><li><p>API Key（密钥）：没有可以先选 No</p></li><li><p>Enable hooks（自动执行）：Skip for now</p></li><li><p>How do you want to hatch your bot（以什么方式启动🦞）：选择 Open the Web UI 启动</p></li></ul><p>会自动在浏览器打开 <a href="http://127.0.0.1:18789/chat?session=main" target="_blank" rel="noreferrer">http://127.0.0.1:18789/chat?session=main</a></p><p>如果出现聊天界面，说明配置成功。</p>',39)])])}const k=i(l,[["render",p]]);export{u as __pageData,k as default};
